import{_ as t,o as a,c as r,a3 as i}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"Platform Architecture Freeze","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Platform Architecture Freeze | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/getting-started/platform-freeze"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Platform Architecture Freeze | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/getting-started/platform-freeze"}]]},"headers":[],"relativePath":"getting-started/platform-freeze.md","filePath":"getting-started/platform-freeze.md","lastUpdated":1784758619000}'),o={name:"getting-started/platform-freeze.md"};function s(l,e,n,d,c,u){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="platform-architecture-freeze" tabindex="-1">Platform Architecture Freeze <a class="header-anchor" href="#platform-architecture-freeze" aria-label="Permalink to &quot;Platform Architecture Freeze&quot;">​</a></h1><p>The platform foundation is <strong>locked</strong>. From this point forward, do not redesign core subsystems unless the change addresses a <strong>critical security issue</strong>, <strong>data integrity issue</strong>, or <strong>production bug</strong>.</p><p>Business capability ships as <strong>modules</strong> on top of this foundation. The first reference module is <strong>Leads</strong>; every later module (Tasks, Communication Templates, Invoices, Inventory, etc.) must mirror that structure. Cross-cutting reusable modules (e.g. Communication Templates) still follow the same licensing + permission + migrate-only registration rules.</p><h2 id="locked-subsystems" tabindex="-1">Locked subsystems <a class="header-anchor" href="#locked-subsystems" aria-label="Permalink to &quot;Locked subsystems&quot;">​</a></h2><p>Do <strong>not</strong> redesign:</p><table tabindex="0"><thead><tr><th>Area</th><th>Includes</th></tr></thead><tbody><tr><td>Authentication</td><td>Central + Tenant auth, shared tenant login, email verification, password reset, sessions, remember me, lockout</td></tr><tr><td>Tenancy</td><td>Workspace resolution, isolation, middleware, domain resolver, white-label readiness</td></tr><tr><td>Authorization</td><td>Modules = licensing; Roles/Permissions = RBAC (Spatie); <code>module:</code> + <code>can:</code> middleware. No Features, Plans, or Limits</td></tr><tr><td>Billing</td><td>Marketplace, module subscriptions, consolidated billing, invoices/payments foundation, gateway abstraction, Stripe driver</td></tr><tr><td>Configuration</td><td>Central defaults → Tenant overrides → System defaults (branding, SMTP, locale, currency, timezone)</td></tr><tr><td>Security</td><td>Audit logs, impersonation, session/workspace isolation, payment security</td></tr></tbody></table><h2 id="allowed-changes" tabindex="-1">Allowed changes <a class="header-anchor" href="#allowed-changes" aria-label="Permalink to &quot;Allowed changes&quot;">​</a></h2><ul><li><strong>Extend</strong> existing implementations (new catalog rows, permissions, routes, services, UI pages).</li><li>Fix critical defects, security holes, or data-integrity bugs.</li><li>Add domain events, listeners, and notifications <strong>inside a module</strong> following the <a href="/developer-guide/module-development">Module Development Standard</a>.</li></ul><h2 id="forbidden-without-explicit-approval" tabindex="-1">Forbidden without explicit approval <a class="header-anchor" href="#forbidden-without-explicit-approval" aria-label="Permalink to &quot;Forbidden without explicit approval&quot;">​</a></h2><ul><li>Introducing a Laravel Modules package or plugin auto-discovery layer</li><li>Repositories abstraction for domain code</li><li>Reintroducing Features / Plans / usage limits</li><li>Divergent Central vs Tenant shell redesigns</li><li>Parallel billing, auth, or settings systems inside a module</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/getting-started/product-roadmap">Product Roadmap</a></li><li><a href="/architecture/">Architecture</a></li><li><a href="/architecture/module-architecture">Module Architecture</a></li><li><a href="/architecture/module-dependencies">Module Dependencies</a></li><li><a href="/architecture/module-licensing">Module Licensing</a></li><li><a href="/developer-guide/module-development">Module Development Standard</a></li><li><a href="/developer-guide/entitlements">Entitlements</a></li><li><a href="/developer-guide/shared-ui">Shared UI</a></li></ul>',12)])])}const h=t(o,[["render",s]]);export{p as __pageData,h as default};
